import{_ as e,o as r,c as t,ag as o}from"./chunks/framework.BWGJuBbb.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"tips/faq.md","filePath":"tips/faq.md","lastUpdated":1773586478000}'),l={name:"tips/faq.md"};function i(n,a,s,h,d,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><blockquote><p>자주 묻는 질문과 답변을 모았습니다.</p></blockquote><h2 id="cowork와-일반-chatgpt-claude-웹은-뭐가-다른가요" tabindex="-1">Cowork와 일반 ChatGPT/Claude 웹은 뭐가 다른가요? <a class="header-anchor" href="#cowork와-일반-chatgpt-claude-웹은-뭐가-다른가요" aria-label="Permalink to &quot;Cowork와 일반 ChatGPT/Claude 웹은 뭐가 다른가요?&quot;">​</a></h2><p>가장 큰 차이는 <strong>내 컴퓨터 파일에 접근</strong>할 수 있다는 점입니다. 웹 AI에게는 파일을 복사-붙여넣기 해야 하지만, Cowork는 파일명만 말하면 직접 읽고, 수정하고, 새 파일을 만들어줍니다.</p><h2 id="내-파일이-외부로-유출될-수-있나요" tabindex="-1">내 파일이 외부로 유출될 수 있나요? <a class="header-anchor" href="#내-파일이-외부로-유출될-수-있나요" aria-label="Permalink to &quot;내 파일이 외부로 유출될 수 있나요?&quot;">​</a></h2><p>회사에서 Enterprise 또는 Team Plan을 사용 중이라면, 데이터가 AI 학습에 사용되지 않습니다. 다만 대화 내용은 Anthropic 서버를 통해 처리되므로, <strong>회사 보안 정책</strong>을 반드시 확인하세요.</p><h2 id="무료로-사용할-수-있나요" tabindex="-1">무료로 사용할 수 있나요? <a class="header-anchor" href="#무료로-사용할-수-있나요" aria-label="Permalink to &quot;무료로 사용할 수 있나요?&quot;">​</a></h2><p>Claude Desktop 자체는 무료로 설치할 수 있고, 기본 대화 기능도 무료입니다. 하지만 Cowork의 고급 기능(파일 접근, 도구 사용 등)은 <strong>Pro 이상의 유료 플랜</strong>이 필요합니다.</p><h2 id="한국어도-잘-되나요" tabindex="-1">한국어도 잘 되나요? <a class="header-anchor" href="#한국어도-잘-되나요" aria-label="Permalink to &quot;한국어도 잘 되나요?&quot;">​</a></h2><p>한국어 매우 잘 됩니다! 비즈니스 이메일, 보고서, 기획서 등 업무 문서를 자연스러운 한국어로 작성합니다. 존댓말/반말, 격식체/비격식체도 구분 가능합니다.</p><h2 id="claude가-만든-결과물을-그대로-써도-되나요" tabindex="-1">Claude가 만든 결과물을 그대로 써도 되나요? <a class="header-anchor" href="#claude가-만든-결과물을-그대로-써도-되나요" aria-label="Permalink to &quot;Claude가 만든 결과물을 그대로 써도 되나요?&quot;">​</a></h2><p>네, 사용해도 됩니다. 다만:</p><ul><li><strong>사실 확인:</strong> 수치, 날짜, 고유명사는 반드시 검증</li><li><strong>맥락 확인:</strong> Claude가 모르는 사내 사정이 반영되지 않았을 수 있음</li><li><strong>최종 검토:</strong> 중요한 문서는 보내기 전에 한 번 더 읽어보세요</li></ul><h2 id="엑셀-파일도-읽을-수-있나요" tabindex="-1">엑셀 파일도 읽을 수 있나요? <a class="header-anchor" href="#엑셀-파일도-읽을-수-있나요" aria-label="Permalink to &quot;엑셀 파일도 읽을 수 있나요?&quot;">​</a></h2><p>네! <code>.xlsx</code>, <code>.csv</code>, <code>.tsv</code> 등 다양한 스프레드시트 파일을 읽을 수 있습니다. 매크로나 VBA가 포함된 복잡한 엑셀은 데이터만 읽습니다.</p><h2 id="인터넷이-안-되면-사용할-수-없나요" tabindex="-1">인터넷이 안 되면 사용할 수 없나요? <a class="header-anchor" href="#인터넷이-안-되면-사용할-수-없나요" aria-label="Permalink to &quot;인터넷이 안 되면 사용할 수 없나요?&quot;">​</a></h2><p>네, 인터넷 연결이 필요합니다. 하지만 결과물을 저장한 후에는 오프라인에서도 사용할 수 있습니다.</p><h2 id="claude가-갑자기-이상한-답을-할-때는" tabindex="-1">Claude가 갑자기 이상한 답을 할 때는? <a class="header-anchor" href="#claude가-갑자기-이상한-답을-할-때는" aria-label="Permalink to &quot;Claude가 갑자기 이상한 답을 할 때는?&quot;">​</a></h2><ul><li><strong>다시 설명하기:</strong> 맥락을 다시 잡아주세요</li><li><strong>새 대화 시작:</strong> 너무 길어지면 새 세션을 열고 핵심만 다시 전달</li><li><strong>질문 쪼개기:</strong> 복잡한 요청을 단계별로 나눠서 재시도</li></ul><h2 id="요금은-얼마인가요" tabindex="-1">요금은 얼마인가요? <a class="header-anchor" href="#요금은-얼마인가요" aria-label="Permalink to &quot;요금은 얼마인가요?&quot;">​</a></h2><ul><li><strong>무료:</strong> 기본 대화 기능 (제한적)</li><li><strong>Pro ($20/월):</strong> Cowork 전체 기능, 파일 접근, 도구 사용</li><li><strong>Team ($30/인/월):</strong> 팀 관리, 공유 프로젝트, 관리자 콘솔</li><li><strong>Enterprise:</strong> 맞춤 계약, SSO, 감사 로그, 전담 지원</li></ul><p>회사에서 도입한다면 Team 이상을 추천합니다. 정확한 가격은 <a href="https://claude.ai/pricing" target="_blank" rel="noreferrer">claude.ai/pricing</a>에서 확인하세요.</p><h2 id="동시에-여러-명이-사용할-수-있나요" tabindex="-1">동시에 여러 명이 사용할 수 있나요? <a class="header-anchor" href="#동시에-여러-명이-사용할-수-있나요" aria-label="Permalink to &quot;동시에 여러 명이 사용할 수 있나요?&quot;">​</a></h2><p>Team/Enterprise 플랜은 각 팀원이 개별 계정으로 동시 사용 가능합니다. Pro는 1인 1계정입니다.</p><h2 id="대화가-갑자기-끊기는-이유는" tabindex="-1">대화가 갑자기 끊기는 이유는? <a class="header-anchor" href="#대화가-갑자기-끊기는-이유는" aria-label="Permalink to &quot;대화가 갑자기 끊기는 이유는?&quot;">​</a></h2><p>Claude에게는 한 번에 처리할 수 있는 <strong>컨텍스트 윈도우</strong> (대화 길이 한도)가 있습니다. 대화가 너무 길어지면:</p><ul><li>새 대화를 시작하고 핵심만 다시 전달하세요</li><li>큰 작업은 단계별로 나눠서 요청하세요</li></ul><h2 id="다른-ai-chatgpt-gemini-등-와-같이-써도-되나요" tabindex="-1">다른 AI (ChatGPT, Gemini 등)와 같이 써도 되나요? <a class="header-anchor" href="#다른-ai-chatgpt-gemini-등-와-같이-써도-되나요" aria-label="Permalink to &quot;다른 AI (ChatGPT, Gemini 등)와 같이 써도 되나요?&quot;">​</a></h2><p>물론입니다! 각 도구의 강점이 다르니, 상황에 맞게 골라 쓰면 됩니다. 다만 회사 보안 정책에서 허용하는 도구인지 확인하세요.</p><h2 id="오프라인에서-쓸-수-있는-대안은" tabindex="-1">오프라인에서 쓸 수 있는 대안은? <a class="header-anchor" href="#오프라인에서-쓸-수-있는-대안은" aria-label="Permalink to &quot;오프라인에서 쓸 수 있는 대안은?&quot;">​</a></h2><p>현재 Claude Cowork는 온라인 전용입니다. 오프라인이 필요하다면:</p><ul><li>미리 결과물을 파일로 저장해두세요</li><li>자주 쓰는 템플릿을 로컬에 백업해두세요</li></ul>',32)])])}const g=e(l,[["render",i]]);export{p as __pageData,g as default};
